// PATCH: Cover owner-only permissions for the generated file cache helper.
func TestStoreSetUsesOwnerOnlyPermissions(t *testing.T) {
	cacheDir := filepath.Join(t.TempDir(), "cache")
	store := New(cacheDir, time.Hour)

	store.Set("/transactions?limit=1", json.RawMessage(`{"transactions":[]}`))

	assertOwnerOnlyCachePath(t, cacheDir)
	assertOwnerOnlyCachePath(t, store.path("/transactions?limit=1"))
}

func assertOwnerOnlyCachePath(t *testing.T, path string) {
	t.Helper()
	info, err := os.Stat(path)
	if err != nil {
		t.Fatalf("stat %s: %v", path, err)
	}
	if got := info.Mode().Perm(); got&0o077 != 0 {
		t.Fatalf("%s mode = %#o, want no group/other permissions", path, got)
	}
}
